// Aggregate Stats node code
// Reads Outreach + Replies, computes weekly metrics

const outreachItems = $('Get Outreach Sheet').all();
const repliesItems = $('Get Replies Sheet').all();

// Date range: last 7 days (Mon 00:00 -> Mon 09:00)
const now = new Date();
const periodEnd = new Date(now);
const periodStart = new Date(now);
periodStart.setDate(periodStart.getDate() - 7);

const periodStartISO = periodStart.toISOString();
const periodEndISO = periodEnd.toISOString();

// Filter Outreach: sent in last 7 days
const sentInPeriod = outreachItems.filter(item => {
  const r = item.json;
  if (!r.date_generated && !r.generated_at) return false;
  const dateStr = r.date_generated || r.generated_at;
  const d = new Date(dateStr);
  return d >= periodStart && d <= periodEnd && (r.status === 'sent' || r.status === 'replied');
});

// Filter Replies: received in last 7 days
const repliedInPeriod = repliesItems.filter(item => {
  const r = item.json;
  if (!r.received_at) return false;
  const d = new Date(r.received_at);
  return d >= periodStart && d <= periodEnd;
});

// Counters
const sentCount = sentInPeriod.length;
const repliedCount = repliedInPeriod.length;
const conversionRate = sentCount > 0 ? ((repliedCount / sentCount) * 100).toFixed(1) : '0.0';

// Categories breakdown
const categoryCounts = {
  positive: 0,
  negative: 0,
  out_of_office: 0,
  neutral: 0,
  referral: 0,
  unsubscribe: 0
};

repliedInPeriod.forEach(item => {
  const cat = (item.json.category || 'neutral').toLowerCase();
  if (categoryCounts.hasOwnProperty(cat)) {
    categoryCounts[cat]++;
  } else {
    categoryCounts.neutral++;
  }
});

// Top cities (from matched Outreach by website)
const cityMap = {};
const domainMap = {};
const subjectMap = {};
const responseTimes = [];

repliedInPeriod.forEach(reply => {
  const r = reply.json;
  // Find matching outreach by website
  const outreachMatch = outreachItems.find(o => {
    const ow = (o.json.website || '').toLowerCase().replace(/\/$/, '');
    const rw = (r.outreach_website || '').toLowerCase().replace(/\/$/, '');
    return ow && rw && ow === rw;
  });

  if (outreachMatch) {
    const city = outreachMatch.json.city || 'Unknown';
    const country = outreachMatch.json.country || '';
    cityMap[`${city}|${country}`] = (cityMap[`${city}|${country}`] || 0) + 1;

    // Domain
    const website = outreachMatch.json.website || '';
    const domainMatch = website.match(/\.([a-z]{2,3})(\/|$)/i);
    if (domainMatch) {
      const tld = '.' + domainMatch[1].toLowerCase();
      domainMap[tld] = (domainMap[tld] || 0) + 1;
    }

    // Subject success (only for positive)
    if ((r.category || '').toLowerCase() === 'positive') {
      const subj = outreachMatch.json.subject_a || outreachMatch.json.subject_b || '';
      if (subj) {
        subjectMap[subj] = (subjectMap[subj] || 0) + 1;
      }
    }

    // Response time
    if (outreachMatch.json.generated_at && r.received_at) {
      const sent = new Date(outreachMatch.json.generated_at);
      const recv = new Date(r.received_at);
      const hours = (recv - sent) / (1000 * 60 * 60);
      if (hours > 0 && hours < 720) {
        responseTimes.push(hours);
      }
    }
  }
});

// Country flag map
const flagMap = {
  'NL': '🇳🇱', 'Netherlands': '🇳🇱',
  'PL': '🇵🇱', 'Poland': '🇵🇱',
  'CZ': '🇨🇿', 'Czech Republic': '🇨🇿', 'Czechia': '🇨🇿',
  'DE': '🇩🇪', 'Germany': '🇩🇪',
  'AT': '🇦🇹', 'Austria': '🇦🇹',
  'CH': '🇨🇭', 'Switzerland': '🇨🇭',
  'BE': '🇧🇪', 'Belgium': '🇧🇪'
};

// Top 3 cities
const topCities = Object.entries(cityMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([key, count]) => {
    const [city, country] = key.split('|');
    const flag = flagMap[country] || '🌍';
    return { city, country, flag, count };
  });

// Top 3 domains
const topDomains = Object.entries(domainMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([tld, count]) => ({ tld, count }));

// Best subject
const bestSubject = Object.entries(subjectMap)
  .sort((a, b) => b[1] - a[1])[0];
const bestSubjectText = bestSubject ? bestSubject[0] : 'N/A';

// Avg response time
const avgResponseHours = responseTimes.length > 0
  ? (responseTimes.reduce((a, b) => a + b, 0) / responseTimes.length).toFixed(1)
  : '0';

// Hot leads (positive only)
const hotLeads = repliedInPeriod
  .filter(r => (r.json.category || '').toLowerCase() === 'positive')
  .map(r => {
    const reply = r.json;
    const outreachMatch = outreachItems.find(o => {
      const ow = (o.json.website || '').toLowerCase().replace(/\/$/, '');
      const rw = (reply.outreach_website || '').toLowerCase().replace(/\/$/, '');
      return ow && rw && ow === rw;
    });
    return {
      company: outreachMatch ? (outreachMatch.json.company_name || 'Unknown') : (reply.from_name || reply.from_email),
      city: outreachMatch ? (outreachMatch.json.city || '') : '',
      country: outreachMatch ? (outreachMatch.json.country || '') : '',
      flag: outreachMatch ? (flagMap[outreachMatch.json.country] || '🌍') : '🌍',
      from_email: reply.from_email,
      key_quote: (reply.key_quote || '').slice(0, 100)
    };
  });

// Format dates for display
const formatDate = (d) => {
  const months = ['янв', 'фев', 'мар', 'апр', 'май', 'июн', 'июл', 'авг', 'сен', 'окт', 'ноя', 'дек'];
  return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
};

return [{
  json: {
    report_date: now.toISOString(),
    period_start: periodStartISO,
    period_end: periodEndISO,
    period_start_display: formatDate(periodStart),
    period_end_display: formatDate(periodEnd),
    sent_count: sentCount,
    replied_count: repliedCount,
    conversion_rate: parseFloat(conversionRate),
    positive: categoryCounts.positive,
    negative: categoryCounts.negative,
    out_of_office: categoryCounts.out_of_office,
    neutral: categoryCounts.neutral,
    referral: categoryCounts.referral,
    unsubscribe: categoryCounts.unsubscribe,
    top_cities: topCities,
    top_domains: topDomains,
    best_subject: bestSubjectText,
    avg_response_hours: parseFloat(avgResponseHours),
    hot_leads: hotLeads,
    hot_leads_count: hotLeads.length
  }
}];

// Format Telegram Message node
const stats = $input.first().json;

const escapeHtml = (str) => {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

// Calculate percentages for categories
const totalReplies = stats.replied_count;
const pct = (n) => totalReplies > 0 ? Math.round((n / totalReplies) * 100) : 0;

let msg = `📊 <b>ЕЖЕНЕДЕЛЬНЫЙ ОТЧЕТ AI OUTREACH</b>\n`;
msg += `<i>Период: ${stats.period_start_display} — ${stats.period_end_display}</i>\n\n`;

msg += `📤 <b>Отправлено:</b> ${stats.sent_count} писем\n`;
msg += `📥 <b>Ответили:</b> ${stats.replied_count} (${stats.conversion_rate}%)\n`;
msg += `🔥 <b>Горячих лидов:</b> ${stats.hot_leads_count} (${stats.sent_count > 0 ? ((stats.hot_leads_count / stats.sent_count) * 100).toFixed(1) : '0.0'}%)\n\n`;

// Categories
if (totalReplies > 0) {
  msg += `<b>КАТЕГОРИИ ОТВЕТОВ:</b>\n`;
  if (stats.positive > 0) msg += `🔥 Positive: ${stats.positive} (${pct(stats.positive)}%)\n`;
  if (stats.referral > 0) msg += `👥 Referral: ${stats.referral} (${pct(stats.referral)}%)\n`;
  if (stats.negative > 0) msg += `❌ Negative: ${stats.negative} (${pct(stats.negative)}%)\n`;
  if (stats.out_of_office > 0) msg += `🌴 Out of office: ${stats.out_of_office} (${pct(stats.out_of_office)}%)\n`;
  if (stats.neutral > 0) msg += `🤔 Neutral: ${stats.neutral} (${pct(stats.neutral)}%)\n`;
  if (stats.unsubscribe > 0) msg += `🚫 Unsubscribe: ${stats.unsubscribe} (${pct(stats.unsubscribe)}%)\n`;
  msg += `\n`;
}

// Top cities
if (stats.top_cities && stats.top_cities.length > 0) {
  msg += `🏆 <b>ТОП ГОРОДА:</b>\n`;
  stats.top_cities.forEach(c => {
    msg += `${c.flag} ${escapeHtml(c.city)} — ${c.count} ${c.count === 1 ? 'ответ' : 'ответов'}\n`;
  });
  msg += `\n`;
}

// Top domains
if (stats.top_domains && stats.top_domains.length > 0) {
  msg += `🌐 <b>ТОП ДОМЕНЫ:</b> `;
  msg += stats.top_domains.map(d => `${d.tld} (${d.count})`).join(', ');
  msg += `\n\n`;
}

// Best subject
if (stats.best_subject && stats.best_subject !== 'N/A') {
  const truncSubj = stats.best_subject.length > 60 ? stats.best_subject.slice(0, 57) + '...' : stats.best_subject;
  msg += `📧 <b>Лучший subject:</b> "${escapeHtml(truncSubj)}"\n`;
}

// Avg response time
if (stats.avg_response_hours > 0) {
  msg += `⏱ <b>Среднее время ответа:</b> ${stats.avg_response_hours} часов\n`;
}
msg += `\n`;

// Hot leads
if (stats.hot_leads && stats.hot_leads.length > 0) {
  msg += `🔥 <b>ГОРЯЧИЕ ЛИДЫ ЗА НЕДЕЛЮ:</b>\n`;
  stats.hot_leads.forEach((lead, i) => {
    msg += `${i + 1}. <b>${escapeHtml(lead.company)}</b>`;
    if (lead.city) msg += ` ${lead.flag} ${escapeHtml(lead.city)}`;
    msg += `\n`;
    if (lead.key_quote) msg += `   <i>"${escapeHtml(lead.key_quote)}"</i>\n`;
  });
  msg += `\n`;
}

// Closing
if (stats.hot_leads_count >= 3) {
  msg += `🚀 Отличная неделя! Так держать!`;
} else if (stats.hot_leads_count >= 1) {
  msg += `💪 Есть теплые лиды, продолжай в том же духе!`;
} else if (stats.sent_count > 0) {
  msg += `📈 Hot leads пока нет, но отправка идет. Stay focused.`;
} else {
  msg += `⚠️ За неделю писем не отправлено. Проверь Worker 4 Sender.`;
}

// Prepare hot_leads_json for Sheets
const hotLeadsJson = JSON.stringify(stats.hot_leads || []);

return [{
  json: {
    telegram_message: msg,
    report_date: stats.report_date,
    period_start: stats.period_start_display,
    period_end: stats.period_end_display,
    sent_count: stats.sent_count,
    replied_count: stats.replied_count,
    conversion_rate: stats.conversion_rate,
    positive: stats.positive,
    negative: stats.negative,
    out_of_office: stats.out_of_office,
    neutral: stats.neutral,
    referral: stats.referral,
    unsubscribe: stats.unsubscribe,
    top_city: stats.top_cities[0] ? `${stats.top_cities[0].city}, ${stats.top_cities[0].country}` : '',
    top_domain: stats.top_domains[0] ? stats.top_domains[0].tld : '',
    best_subject: stats.best_subject,
    avg_response_hours: stats.avg_response_hours,
    hot_leads_json: hotLeadsJson
  }
}];
